133→        setSessionId(id);
134→        localStorage.setItem('omega_session', id);
135→        setSidebarOpen(false);
136→      }
137→    } catch (err) { console.error(err); }
138→  };
139→
140→  const startNewChat = () => {
141→    setMessages([]);
142→    setSessionId(null);
143→    setProvider(null);
144→    localStorage.removeItem('omega_session');
145→    setSidebarOpen(false);
146→  };
147→
148→  const vs = processing ? 'thinking' : voice.voiceState;
149→  const stateLabel = processing ? 'Thinking...' : (STATE_LABELS[voice.voiceState] ?? '');
150→
151→  return (
152→    <div className={s.root}>
153→      <div className={s.stars} aria-hidden />
154→
155→      <Sidebar
156→        sessions={sessionList}
157→        activeSessionId={sessionId}
158→        onNewChat={startNewChat}
159→        onSelectSession={loadSession}
160→        isOpen={sidebarOpen}
161→        onToggle={() => setSidebarOpen(o => !o)}
162→      />
163→
164→      <div className={`${s.main} ${sidebarOpen ? s.mainShifted : ''}`}>
165→
166→        <header className={s.topBar}>
167→          <button className={s.menuBtn} onClick={() => setSidebarOpen(o => !o)} aria-label="History">
168→            <span /><span /><span />
169→          </button>
170→          <div className={s.brand}>
171→            <span className={s.brandGlyph}>Ω</span>
172→            <span className={s.brandName}>OmegA</span>
173→          </div>
174→          <div className={s.topRight}>
175→            {provider && <span className={s.badge}>{provider.split('-')[0]}</span>}
176→            <span className={`${s.dot} ${vs === 'thinking' ? s.dotThink : vs !== 'dormant' ? s.dotLive : ''}`} />
177→          </div>
178→        </header>
179→
180→        <div className={s.stage}>
181→          <div className={s.orbClick} onClick={voice.toggle} title="Toggle voice">
182→            <VoiceOrb
183→              voiceState={voice.voiceState}
184→              micLevel={voice.micLevel}
185→              ttsLevel={voice.ttsLevel}
