187→            />
188→          </div>
189→          <p className={`${s.stateLabel} ${s['sl_' + vs]}`}>{stateLabel}</p>
190→          {voice.interim && (
191→            <div className={s.interim}><span>{voice.interim}</span></div>
192→          )}
193→        </div>
194→
195→        {(messages.length > 0 || processing) && (
196→          <div className={s.feed} ref={feedRef}>
197→            {messages.map((m, i) => (
198→              <div key={i} className={`${s.msg} ${m.role === 'user' ? s.msgUser : s.msgOmega}`}>
