195→/* ── Conversation feed ───────────────────────────────────────────── */
196→.feed {
197→  flex: 1;
198→  overflow-y: auto;
199→  overflow-x: hidden;
200→  padding: 0.5rem 1rem 1rem;
201→  display: flex;
202→  flex-direction: column;
203→  gap: 0.65rem;
204→  scroll-behavior: smooth;
205→}
206→
207→.msg {
208→  display: flex;
209→  align-items: flex-start;
210→  gap: 0.6rem;
211→  max-width: min(720px, 92%);
212→  animation: fade-up 0.3s cubic-bezier(0.16,1,0.3,1) both;
213→}
214→.msgUser {
215→  align-self: flex-end;
216→  flex-direction: row-reverse;
217→}
218→.msgOmega {
219→  align-self: flex-start;
220→}
221→
222→.msgGlyph {
223→  font-family: 'Orbitron', monospace;
224→  font-size: 0.75rem;
225→  font-weight: 700;
226→  color: rgba(139,92,246,0.7);
227→  margin-top: 0.2rem;
228→  flex-shrink: 0;
229→  width: 18px;
230→  text-align: center;
231→}
232→
233→.msgText {
234→  font-family: 'Space Grotesk', sans-serif;
235→  font-size: clamp(0.9rem, 2.2vw, 1rem);
236→  line-height: 1.65;
237→  padding: 0.65rem 1rem;
238→  border-radius: 14px;
239→  white-space: pre-wrap;
240→}
241→.msgUser .msgText {
242→  background: rgba(99,102,241,0.18);
243→  border: 1px solid rgba(99,102,241,0.25);
244→  color: rgba(241,245,249,0.92);
245→  border-bottom-right-radius: 4px;
246→}
247→.msgOmega .msgText {
248→  background: rgba(8,8,28,0.72);
249→  border: 1px solid rgba(139,92,246,0.15);
250→  color: rgba(241,245,249,0.88);
251→  border-bottom-left-radius: 4px;
252→  backdrop-filter: blur(8px);
253→}
254→
255→/* ── Thinking dots ───────────────────────────────────────────────── */
256→.dots {
257→  display: flex;
258→  align-items: center;
259→  gap: 4px;
260→  padding: 0.7rem 1rem;
261→  background: rgba(8,8,28,0.72);
262→  border: 1px solid rgba(139,92,246,0.15);
263→  border-radius: 14px;
264→  border-bottom-left-radius: 4px;
265→}
266→.dots span {
267→  width: 6px;
268→  height: 6px;
269→  border-radius: 50%;
270→  background: rgba(139,92,246,0.6);
271→  animation: dot-bounce 1.2s ease-in-out infinite;
272→}
273→.dots span:nth-child(2) { animation-delay: 0.15s; }
274→.dots span:nth-child(3) { animation-delay: 0.30s; }
275→
276→@keyframes dot-bounce {
277→  0%, 80%, 100% { transform: translateY(0);   opacity: 0.3; }
278→  40%            { transform: translateY(-6px); opacity: 1; }
279→}
280→
281→/* ── Error ───────────────────────────────────────────────────────── */
282→.errMsg {
283→  align-self: center;
284→  padding: 0.6rem 1rem;
285→  background: rgba(239,68,68,0.12);
286→  border: 1px solid rgba(239,68,68,0.25);
287→  border-radius: 10px;
288→  color: #fca5a5;
289→  font-size: 0.84rem;
290→  font-family: 'Space Grotesk', sans-serif;
291→}
292→
293→/* ── Bottom bar ──────────────────────────────────────────────────── */
294→.bottom {
295→  flex-shrink: 0;
296→  padding: 0.75rem 1.25rem max(0.75rem, env(safe-area-inset-bottom));
297→  border-top: 1px solid rgba(139,92,246,0.08);
298→  backdrop-filter: blur(20px);
299→  background: rgba(2,2,12,0.6);
300→}
301→
302→.actions {
303→  display: flex;
304→  align-items: center;
305→  justify-content: space-between;
306→}
307→
308→.typeBtn {
309→  display: flex;
310→  align-items: center;
311→  gap: 0.4rem;
312→  background: none;
313→  border: 1px solid rgba(139,92,246,0.18);
314→  color: rgba(196,181,253,0.55);
315→  font-family: 'Space Grotesk', sans-serif;
316→  font-size: 0.8rem;
317→  padding: 0.45rem 0.85rem;
318→  border-radius: 20px;
319→  cursor: pointer;
320→  transition: all 0.2s;
321→  letter-spacing: 0.04em;
322→}
323→.typeBtn:hover {
324→  background: rgba(139,92,246,0.1);
325→  color: rgba(196,181,253,0.9);
326→  border-color: rgba(139,92,246,0.35);
327→}
328→
329→.micBtn {
330→  width: 48px;
331→  height: 48px;
332→  border-radius: 50%;
333→  border: 1.5px solid rgba(99,102,241,0.25);
334→  background: rgba(8,8,28,0.8);
335→  color: rgba(99,102,241,0.5);
336→  display: flex;
337→  align-items: center;
338→  justify-content: center;
339→  cursor: pointer;
340→  transition: all 0.3s cubic-bezier(0.16,1,0.3,1);
341→  backdrop-filter: blur(10px);
342→}
343→.micBtn:hover {
344→  border-color: rgba(99,102,241,0.5);
345→  color: rgba(99,102,241,0.9);
346→  box-shadow: 0 0 16px rgba(99,102,241,0.25);
347→}
348→.micActive {
349→  border-color: rgba(139,92,246,0.6);
350→  background: rgba(99,102,241,0.15);
351→  color: rgba(196,181,253,0.9);
352→  box-shadow: 0 0 20px rgba(99,102,241,0.3), inset 0 0 12px rgba(139,92,246,0.08);
353→  animation: mic-breathe 2s ease-in-out infinite;
354→}
355→
356→@keyframes mic-breathe {
357→  0%, 100% { box-shadow: 0 0 20px rgba(99,102,241,0.3), inset 0 0 12px rgba(139,92,246,0.08); }
358→  50%       { box-shadow: 0 0 32px rgba(99,102,241,0.5), inset 0 0 16px rgba(139,92,246,0.12); }
359→}
360→
361→/* ── Text input row ──────────────────────────────────────────────── */
362→.textRow {
363→  display: flex;
364→  align-items: center;
365→  gap: 0.5rem;
366→  background: rgba(8,8,28,0.8);
367→  border: 1px solid rgba(139,92,246,0.2);
368→  border-radius: 14px;
369→  padding: 0.4rem 0.6rem;
370→  backdrop-filter: blur(12px);
371→}
372→.textArea {
373→  flex: 1;
374→  background: none;
375→  border: none;
376→  outline: none;
377→  resize: none;
378→  color: rgba(241,245,249,0.9);
379→  font-family: 'Space Grotesk', sans-serif;
380→  font-size: 0.95rem;
381→  line-height: 1.5;
382→  max-height: 120px;
383→  overflow-y: auto;
384→}
385→.textArea::placeholder { color: rgba(241,245,249,0.25); }
386→
387→.sendBtn {
388→  width: 34px;
389→  height: 34px;
390→  border-radius: 10px;
391→  border: none;
392→  background: rgba(99,102,241,0.7);
393→  color: white;
394→  font-size: 1.3rem;
395→  line-height: 1;
396→  cursor: pointer;
397→  display: flex;
398→  align-items: center;
399→  justify-content: center;
400→  transition: background 0.2s;
401→  flex-shrink: 0;
402→}
403→.sendBtn:hover:not(:disabled) { background: rgba(99,102,241,1); }
404→.sendBtn:disabled { opacity: 0.3; cursor: default; }
405→
406→.closeBtn {
407→  background: none;
408→  border: none;
409→  color: rgba(241,245,249,0.3);
410→  font-size: 0.8rem;
411→  cursor: pointer;
412→  padding: 4px;
413→  border-radius: 6px;
414→  transition: color 0.2s;
415→}
416→.closeBtn:hover { color: rgba(241,245,249,0.7); }
417→
418→/* ── Shared keyframes ────────────────────────────────────────────── */
419→@keyframes fade-up {
420→  from { opacity: 0; transform: translateY(10px); }
421→  to   { opacity: 1; transform: translateY(0); }
422→}
423→
424→/* ── Mobile ──────────────────────────────────────────────────────── */
425→@media (max-width: 480px) {
426→  .stage { padding-top: clamp(1.5rem, 5vh, 3rem); }
427→  .topBar { padding: 0.7rem 1rem; }
428→  .feed { padding: 0.5rem 0.75rem 1rem; }
429→  .bottom { padding: 0.6rem 1rem max(0.6rem, env(safe-area-inset-bottom)); }
430→}
431→
